const currentStatus: AllowedStatus = 'active';  // 'banned' and 'inactive' are excluded

type Mixed = 'text' | 'image' | 'video' | 'audio';

type Media = Extract<Mixed, 'image' | 'video' | 'audio'>;

const mediaType: Media = 'video';

